package com.inventory.auth.dto;
import com.inventory.auth.entity.Role;
import jakarta.validation.constraints.*;
public class UserDto { private Long id; @NotBlank(message="Username is required") @Size(min=3,max=50,message="Username must be between 3 and 50 characters") private String username; @NotBlank(message="Password is required") @Size(min=6,message="Password must be at least 6 characters") private String password; @NotBlank(message="Email is required") @Email(message="Invalid email format") private String email; private Role role; public Long getId(){return id;} public void setId(Long id){this.id=id;} public String getUsername(){return username;} public void setUsername(String username){this.username=username;} public String getPassword(){return password;} public void setPassword(String password){this.password=password;} public String getEmail(){return email;} public void setEmail(String email){this.email=email;} public Role getRole(){return role;} public void setRole(Role role){this.role=role;} }
